import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Routes } from '@angular/router';

import { BQBComponent } from './bqb/bqb.component';
import { BUNComponent } from './bun/bun.component';
import { CBKComponent } from './cbk/cbk.component';
import { RRMComponent } from './rrm/rrm.component';


const routes: Routes = [{
  path: 'bqb',
  component: BQBComponent
}, {
  path: 'bun',
  component: BUNComponent
}, {
  path: 'cbk',
  component: CBKComponent
}, {
  path: 'rrm',
  component: RRMComponent
}];

@NgModule({
  declarations: [],
  imports: [
    CommonModule,
    RouterModule.forChild(routes)
  ],
  exports: [RouterModule]
})
export class BAIRoutingModule { }
